changeSet.sql:
DROP TABLE IF EXISTS finding_to_control_maturity;

ALTER TABLE findings ADD COLUMN IF NOT EXISTS control_maturity_id integer DEFAULT NULL;
ALTER TABLE findings DROP CONSTRAINT IF EXISTS fk_findings_to_control_maturity;
ALTER TABLE findings ADD CONSTRAINT fk_findings_to_control_maturity FOREIGN KEY (control_maturity_id) REFERENCES control_maturities (id);
CREATE INDEX i_findings_control_maturity ON findings (control_maturity_id);


DROP TABLE IF EXISTS sys_req_ctrl_test_result_to_control_maturity;

ALTER TABLE system_requirement_control_test_results ADD COLUMN IF NOT EXISTS control_maturity_id integer DEFAULT NULL;
ALTER TABLE system_requirement_control_test_results DROP CONSTRAINT IF EXISTS fk_sys_req_ctrl_test_results_to_control_maturity;
ALTER TABLE system_requirement_control_test_results ADD CONSTRAINT fk_sys_req_ctrl_test_results_to_control_maturity FOREIGN KEY (control_maturity_id) REFERENCES control_maturities (id);
CREATE INDEX i_sys_req_ctrl_test_results_control_maturity ON system_requirement_control_test_results (control_maturity_id);


DROP TABLE IF EXISTS org_req_ctrl_test_result_to_control_maturity;

ALTER TABLE organization_requirement_control_test_results ADD COLUMN IF NOT EXISTS control_maturity_id integer DEFAULT NULL;
ALTER TABLE organization_requirement_control_test_results DROP CONSTRAINT IF EXISTS fk_org_req_ctrl_test_results_to_control_maturity;
ALTER TABLE organization_requirement_control_test_results ADD CONSTRAINT fk_org_req_ctrl_test_results_to_control_maturity FOREIGN KEY (control_maturity_id) REFERENCES control_maturities (id);
CREATE INDEX i_org_req_ctrl_test_results_control_maturity ON organization_requirement_control_test_results (control_maturity_id);
